          <button id=\"close-button\" class=\"modal-default-button text-2xl py-1\" @click=\"closeModal()\">&times;</button>\n                    </div>\n\n                     <attachment-assignment :url=\"url\"  :id=\"this.assignment_id\"></attachment-assignment>\n                   <!--  <div class=\"modal-body\">\n                        <div class=\"flex items-center\">\n                            <div class=\"w-full lg:w-1/4\"> \n                                <label for=\"assignment_file\" class=\"tw-form-label\">Assignment File</label>\n                            </div>\n                            <div class=\"my-2 w-full lg:w-3/4\">\n                                <input type=\"file\" name=\"assignment_file\" @change=\"OnFileSelected\" id=\"assignment_file\" class=\"tw-form-control w-full\">\n                                <span v-if=\"errors.assignment_file\" class=\"text-red-500 text-xs font-semibold\">{{errors.assignment_file[0]}}</span>\n                            </div>\n                        </div>\n                    </div>\n\n                    <div class=\"my-6\">\n                        <a href=\"#\" class=\"btn btn-submit blue-bg text-white rounded px-3 py-1 mr-3 text-sm font-medium\" @click=\"submitAssignment()\">Submit</a>\n                    </div> -->\n                </div>\n            </div>\n        </div>\n        <div v-if=\"this.show == 'view'\" class=\"modal modal-mask\">\n            <div class=\"modal-wrapper px-4\">\n                <div class=\"modal-container w-full  max-w-md px-8 mx-auto\">\n                    <div class=\"modal-header flex justify-between items-center\">\n                        <h2>Assignment Marks</h2>\n                        <button id=\"close-button\" class=\"modal-default-button text-2xl py-1\" @click=\"closeModal()\">&times;</button>\n                    </div>\n                    <div class=\"modal-body\">\n                        <div class=\"flex\">\n                            <div class=\"w-full lg:w-1/4\">\n                                <label for=\"date\" class=\"tw-form-label\">Attached File</label>\n                            </div>\n                            <div class=\"flex flex-wrap w-full lg:w-3/4\">\n                                <div class=\"m-1\" v-for=\"list in assignment.assignment_file\">\n                                    <img :src=\"list.path\" class=\"w-25 h-25\">\n                                </div>\n                            </div>\n                        </div>\n                    </div>\n                    <div class=\"modal-body\" v-if=\"assignment.obtained_marks != null\">\n                        <div class=\"flex items-center\">\n                            <div class=\"w-full lg:w-1/4\"> \n                                <label for=\"obtained_marks\" class=\"tw-form-label\">Marks</label>\n                            </div>\n                            <div class=\"my-2 w-full lg:w-3/4\">\n                                <p>{{ assignment.obtained_marks }} / {{ this.marks }}</p>\n                            </div>\n                        </div>\n                        <div class=\"flex items-center\">\n                            <div class=\"w-full lg:w-1/4\"> \n                                <label for=\"comments\" class=\"tw-form-label\">Comments</label>\n                            </div>\n                            <div class=\"my-2 w-full lg:w-3/4\">\n                                <p>{{ assignment.comments }}</p>\n                            </div>\n                        </div>\n                    </div>\n                    <div class=\"modal-body\" v-else>\n                        <div class=\"flex items-center\">\n                            <div class=\"my-2 w-full lg:w-3/4\">\n                                <p>No Marks Added</p>\n                            </div>\n                        </div>\n                    </div>\n                </div>\n            </div>\n        </div>\n    </div>\n</template>\n\n<script>\n    import { bus } from \"../../../app\";\n    export default {\n        props:['url' , 'type' , 'scope' , 'hidecolumns', 'searchquery'],\n        data () {\n            return {\n                assignments:[],\n                assignment:[],\n                showCompleted:'',\n                student_assignment_id:'',\n                assignment_file:'',\n                assignment_id:'',\n                marks:'',\n                show:0,\n                search:'',\n                params:{},\n                errors:[],\n                success:null, \n                total: 0,\n                page: 1,\n                page_count: 0,\n            }\n        },\n\n        methods:\n        {\n            getData(page=1)\n            {\n                axios.get(this.url+'/'+this.type+'/assignment/show/list?standardLink_id='+this.scope+'&showCompleted='+this.showCompleted+'&search='+this.search+'&page='+page).then(response => {\n                    this.assignments    = response.data.data;\n                    this.page_count     = response.data.meta.last_page;\n                    this.total          = response.data.meta.total;\n                    console.log(this.assignments);    \n                });\n            },\n\n            trim(string) \n            {\n                return string.substring(0,140) + '...';\n            },\n\n            searchList()\n            {\n                this.getData();\n            },\n\n            resetForm()\n            {\n                this.search = '';\n                this.getData();\n            },\n\n            showCompletedAssignment(e)\n            {\n                this.getData();\n            },\n\n            deleteassignment(id) \n            {\n                var thisswal = this;\n                swal({\n                    title: 'Are you sure',\n                    text: 'Do you want to delete this assignment ?',\n                    icon: \"info\",\n                    buttons: [\n                        'No',\n                        'Yes'\n                    ],\n                    dangerMode: true,\n                }).then(function(isConfirm) {\n                    if (isConfirm) \n                    {\n                        if(thisswal.type == 'teacher')\n                        {\n                            axios.get(thisswal.url+ '/teacher/assignment/delete/'+ id).then(response => {\n                                thisswal.success = response.data.success;\n                                window.location.reload();\n                            }); \n                        }\n                        else if(thisswal.type == 'student')\n                        {\n                            axios.get(thisswal.url+ '/student/assignment/delete/'+ id).then(response => {\n                                thisswal.success = response.data.success;\n                                window.location.reload();\n                            }); \n                        }\n                    }\n                    else \n                    {\n                        swal(\"Cancelled\");\n                    }\n                });\n            },\n\n            showModal(id)\n            {\n                this.show = 'add';\n                this.assignment_id = id;\n            },\n\n            getEditData(student_assignment_id,marks)\n            {       \n                axios.get('/student/assignment/show/edit/list/'+student_assignment_id).then(response => {\n                    this.assignment = response.data\n                    this.marks          = marks;\n                });\n            },\n\n            viewMarks(id,marks)\n            {\n                this.getEditData(id,marks);\n                this.show = 'view';\n            },\n\n            closeModal()\n            {\n                this.show = 0;\n            },\n\n            submitAssignment()\n            {\n                this.errors=[];\n                this.success=null; \n\n                let formData = new FormData();\n                \n                formData.append('assignment_file',this.assignment_file);        \n                formData.append('assignment_id',this.assignment_id);        \n                     \n                axios.post('/student/assignment/add',formData,{headers: {'Content-Type': 'multipart/form-data'}}).then(response => {     \n                    this.success = response.data.success;\n                    this.closeModal();\n                    window.location.reload();\n                }).catch(error => {\n                    this.errors = error.response.data.errors;\n                });\n            },\n\n            OnFileSelected(event)\n            {\n                this.assignment_file = event.target.files[0];\n            },\n        },\n  \n        created()\n        { \n            this.getData();\n            bus.$on('success',data =>{\n                if(data != null)\n                {\n                    this.closeModal();\n                    this.success = data.success;\n                    window.location.reload();\n                }\n            });\n        }\n    }\n</script>\n\n<style scoped>\n    .modal-mask {\n        position: fixed;\n        z-index: 9998;\n        top: 0;\n        left: 0;\n        width: 100%;\n        height: 100%;\n        background-color: rgba(0, 0, 0, .5);\n        display: table;\n        transition: opacity .3s ease;\n    }\n\n    .modal-wrapper {\n        display: table-cell;\n        vertical-align: middle;\n        overflow:auto;\n    }\n\n    .modal-container-new {\n        margin: 0px auto;\n        /*padding: 20px 30px;*/\n        background-color: #fff;\n        border-radius: 2px;\n        box-shadow: 0 2px 8px rgba(0, 0, 0, .33);\n        transition: all .3s ease;\n        /*height: 500px;*/\n        overflow:auto;\n    }\n\n    .modal-container {\n        margin: 0px auto;\n        /*padding: 20px 30px;*/\n        background-color: #fff;\n        border-radius: 2px;\n        box-shadow: 0 2px 8px rgba(0, 0, 0, .33);\n        transition: all .3s ease;\n        max-height: 500px;\n        overflow:auto;\n    }\n\n    .modal-header h3 {\n        margin-top: 0;\n        color: #42b983;\n    }\n\n    .modal-body {\n        margin: 20px 0;\n    }\n\n    .modal-default-button {\n        float: right;\n    }\n\n    /*\n     * The following styles are auto-applied to elements with\n     * transition=\"modal\" when their visibility is toggled\n     * by Vue.js.\n     *\n     * You can easily play with the modal transition by editing\n     * these styles.\n     */\n    .modal-enter {\n        opacity: 0;\n    }\n\n    .modal-leave-active {\n        opacity: 0;\n    }\n\n    .modal-enter .modal-container,\n    .modal-leave-active .modal-container {\n        -webkit-transform: scale(1.1);\n        transform: scale(1.1);\n    }\n</style>"],"sourceRoot":""}]);
